import { Component } from '@angular/core';

@Component({

selector:'app-home',

templateUrl:'./home.component.html',

styleUrls:['./home.component.scss']

})


export class HomeComponent{


login(){

alert("Login Page");

}


goContact(){

document
.getElementById("contact")
?.scrollIntoView({
behavior:"smooth"
});

}



send(){

alert("Message Sent Successfully");

}


}
